exercises.solution:
class TooYoungError(Exception):
    pass

def check_age(age):
    if age < 18:
        raise TooYoungError("Must be 18 or older")

try:
    check_age(16)
except TooYoungError as e:
    print("Error:", e)

check_age(21)
print("Age 21 is fine")

