exercises.solution:
class NegativeValueError(ValueError):
    def __init__(self, value):
        self.value = value
        super().__init__(f"Value cannot be negative: {value}")

def square_root(n):
    if n < 0:
        raise NegativeValueError(n)
    return n ** 0.5

try:
    square_root(-9)
except NegativeValueError as e:
    print(e)
    print("Bad value was:", e.value)
